import { derived, writable } from 'svelte/store';
import { Sudoku } from '../../../domain/Sudoku.js';
import { Game } from '../../../domain/Game.js';
import { generateSudoku } from '@sudoku/sudoku';
import { decodeSencode, encodeSudoku } from '@sudoku/sencode';
import { candidates } from './candidates.js';

// 全局游戏实例
let gameInstance = null;

// 深拷贝 9x9 数组
function deepCopyGrid(grid) {
  if (!grid) return Array(9).fill().map(() => Array(9).fill(0));
  return grid.map(row => [...row]);
}

// 创建空棋盘
const emptyGrid = Array(9).fill().map(() => Array(9).fill(0));

// 创建 grid store
function createGrid() {
  const { subscribe, set } = writable(deepCopyGrid(emptyGrid));

  return {
    subscribe,
    
    generate(difficulty) {
	  // 清空候选数 store
      candidates.reset();

      const givens = generateSudoku(difficulty);
      const sudoku = new Sudoku(givens);
      gameInstance = new Game({ sudoku });
      const newGrid = gameInstance.getGrid();
      set(deepCopyGrid(newGrid));
    },
    
    decodeSencode(sencode) {
	  // 清空候选数 store
      candidates.reset(); 

      const givens = decodeSencode(sencode);
      const sudoku = new Sudoku(givens);
      gameInstance = new Game({ sudoku });
      set(deepCopyGrid(gameInstance.getGrid()));
    },
    
    set(newGrid) {
      set(deepCopyGrid(newGrid));
    },
    
    get(gridStore, x, y) {
      if (!gridStore) return 0;
      return gridStore[y]?.[x] || 0;
    },
    
    getSencode(gridStore) {
      if (!gridStore) return '';
      return encodeSudoku(gridStore);
    },
  };
}

export const grid = createGrid();

// 创建 userGrid store
function createUserGrid() {
  const { subscribe, set } = writable(deepCopyGrid(emptyGrid));

  // 当 grid 变化时，更新 userGrid
  grid.subscribe($grid => {
    if ($grid && $grid.length === 9) {
      set(deepCopyGrid($grid));
    }
  });

  return {
	subscribe,
	
	isFixed: (x, y) => {
		if (!gameInstance) return false;
		return gameInstance.isFixed(y, x);
	},
	
	set: (pos, value) => {
		if (!gameInstance) return;
		if (gameInstance.isFixed(pos.y, pos.x)) return;
		const result = gameInstance.guess(pos.y, pos.x, value);
		if (result.success) {
			grid.set(gameInstance.getGrid());
		}
	},
	
	undo: () => {
		if (!gameInstance) return;
		const result = gameInstance.undo();
		if (result.success) {
			grid.set(gameInstance.getGrid());
		}
	},
	
	redo: () => {
		if (!gameInstance) return;
		const result = gameInstance.redo();
		if (result.success) {
			grid.set(gameInstance.getGrid());
		}
	},
	
	applyHint: (pos) => {
		if (!gameInstance) return;
		import('@sudoku/stores/hints').then(({ hints }) => {
			import('@sudoku/sudoku').then(({ solveSudoku }) => {
				const solved = solveSudoku(gameInstance.getGivens());
				const correctValue = solved[pos.y][pos.x];
				if (gameInstance.getCell(pos.y, pos.x) === 0) {
					const result = gameInstance.guess(pos.y, pos.x, correctValue);
					if (result.success) {
						grid.set(gameInstance.getGrid());
						hints.useHint();
					}
				}
			});
		});
	},
	
	//提示功能
	getHintInfo: () => {
		if (!gameInstance) return null;
		return gameInstance.getHint();
	},
	
	getPossibleCandidates: (pos) => {
		if (!gameInstance) return [];
		return gameInstance.getPossibleCandidates(pos.y, pos.x);
	},
	
	//探索模式
	enterExplore: (pos, value) => {
		if (!gameInstance) return false;
		const success = gameInstance.enterExplore(pos.y, pos.x, value);
		if (success) {
			const exploreGrid = gameInstance.getExploreGrid();
			if (exploreGrid) {
				grid.set(deepCopyGrid(exploreGrid));
			}
		}
		return success;
	},
	
	exploreSet: (pos, value) => {
		if (!gameInstance) return { success: false, reason: 'no_game_instance' };
		const result = gameInstance.exploreGuess(pos.y, pos.x, value);
		if (result.success) {
			const exploreGrid = gameInstance.getExploreGrid();
			if (exploreGrid) {
				grid.set(deepCopyGrid(exploreGrid));
			}
		}
		return result;
	},
	
	exploreUndo: () => {
		if (!gameInstance) return false;
		const success = gameInstance.exploreUndo();
		if (success) {
			const exploreGrid = gameInstance.getExploreGrid();
			if (exploreGrid) {
				grid.set(deepCopyGrid(exploreGrid));
			}
		}
		return success;
	},
	
	exploreRedo: () => {
		if (!gameInstance) return false;
		const success = gameInstance.exploreRedo();
		if (success) {
			const exploreGrid = gameInstance.getExploreGrid();
			if (exploreGrid) {
				grid.set(deepCopyGrid(exploreGrid));
			}
		}
		return success;
	},
	
	commitExplore: () => {
		if (!gameInstance) return false;
		const success = gameInstance.commitExplore();
		if (success) {
			grid.set(gameInstance.getGrid());
		}
		return success;
	},
	
	abandonExplore: () => {
		if (!gameInstance) return false;
		const success = gameInstance.abandonExplore();
		if (success) {
			grid.set(gameInstance.getGrid());
		}
		return success;
	},
	
	isInExplore: () => {
		return gameInstance ? gameInstance.isInExplore() : false;
	},
	
	isExploreFailed: () => {
		return gameInstance ? gameInstance.isExploreFailed() : false;
	},
	
	getExploreBranchTree: () => {
		if (!gameInstance || !gameInstance.getExplore) return null;
		const explore = gameInstance.getExplore();
		return explore ? explore.getBranchTree() : null;
	}
	};
}

export const userGrid = createUserGrid();

// invalidCells store
export const invalidCells = derived(userGrid, $userGrid => {
  const _invalidCells = [];
  const BOX_SIZE = 3;
  const SUDOKU_SIZE = 9;

  if (!$userGrid) return [];

  const addInvalid = (x, y) => {
    const xy = x + ',' + y;
    if (!_invalidCells.includes(xy)) _invalidCells.push(xy);
  };

  for (let y = 0; y < SUDOKU_SIZE; y++) {
    for (let x = 0; x < SUDOKU_SIZE; x++) {
      const value = $userGrid[y]?.[x];
      if (value) {
        for (let i = 0; i < SUDOKU_SIZE; i++) {
          if (i !== x && $userGrid[y]?.[i] === value) addInvalid(x, y);
          if (i !== y && $userGrid[i]?.[x] === value) addInvalid(x, i);
        }
        const startY = Math.floor(y / BOX_SIZE) * BOX_SIZE;
        const startX = Math.floor(x / BOX_SIZE) * BOX_SIZE;
        for (let row = startY; row < startY + BOX_SIZE; row++) {
          for (let col = startX; col < startX + BOX_SIZE; col++) {
            if (row !== y && col !== x && $userGrid[row]?.[col] === value) {
              addInvalid(col, row);
            }
          }
        }
      }
    }
  }
  return _invalidCells;
}, []);

export function getGameInstance() {
  return gameInstance;
}